10.query:
fetch logs //, scanLimitGBytes: 500, samplingRatio: 1000
| filter matchesValue(winlog.eventid, "4740") OR matchesValue(winlog.eventid, "4725") OR matchesValue(winlog.eventid, "4625") OR matchesValue(winlog.eventid, "4771")
| filterout matchesPhrase(content, "The EventSystem sub system is suppressing duplicate event log entries for a duration of 86400 seconds")
| fieldsAdd EventType = if(winlog.eventid == "4740", "Lockout",
    else: if(winlog.eventid == "4725", "Disabled",
    else: if(winlog.eventid == "4625", "Failed Logon",
    else: "Kerberos Fail")))
| makeTimeseries count(), by: EventType, time:{timestamp}, interval:30m
